export const DASHBOARD_JS = `
const state={monitor:null,activity:{recentTasks:[]},events:[],alerts:[],recommendations:[],filter:'all',paused:false,technical:false,selected:null,collaborationContext:null,collaborationEvidence:new Set(),collaborationBundle:null,collaborationPrompt:''};const $=id=>document.getElementById(id);const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const runtime=()=>state.monitor?.lastEventBySource?.process?.after||{};const git=()=>state.monitor?.lastEventBySource?.git?.after||{};const task=()=>state.activity?.currentTask;const rel=v=>{if(!v)return'暂无';const s=Math.max(0,Math.round((Date.now()-new Date(v).getTime())/1000));return s<5?'刚刚':s<60?s+' 秒前':s<3600?Math.floor(s/60)+' 分钟前':Math.floor(s/3600)+' 小时前'};
const names={'runtime.snapshot':'完成运行状态检查','runtime.changed':'Hermes 状态已更新','runtime.degraded':'运行状态异常','runtime.ready':'Hermes 已准备就绪','log.error':'日志出现错误','tool.observed':'Hermes 正在使用工具','tool.completed':'工具执行完成','task.started':'任务开始','task.observed':'任务有新进展','task.completed':'任务完成','git.snapshot':'完成 Git 状态检查','git.workspace_changed':'代码工作区发生变化','git.head_changed':'Git 版本发生变化','filesystem.added':'新增文件','filesystem.changed':'修改文件','filesystem.deleted':'删除文件','log.watch_started':'开始监听日志'};const friendly=e=>names[e.action]||e.action.replace(/[._]/g,' ');const source=s=>({log:'Hermes 日志',process:'运行状态',git:'Git',filesystem:'项目文件',tool:'工具',runtime:'系统'}[s]||s);const category=e=>e.action==='log.error'||e.result?.ok===false?'error':e.source==='git'||e.source==='filesystem'?'change':e.action.startsWith('tool.')?'tool':e.taskId||e.action.startsWith('task.')?'task':'other';
function health(){const r=runtime(),checks=[r.gateway?.state==='running',r.health?.ok===true,(r.ports||[]).length>0&&(r.ports||[]).every(p=>p.listening),(r.processes||[]).some(p=>p.name==='Hermes')];return{score:Math.round(checks.filter(Boolean).length/checks.length*100),checks}}
function renderMetrics(){const h=health(),t=task(),dirty=git().entries?.length||0,items=[['◇','blue','总事件',state.monitor?.totalEvents||0,'监控已规范化'],['✓','green','任务进度',t?t.observedProgress+'%':'—',t?t.status:'等待任务 ID'],['♢','purple','健康评分',h.score+'%',h.score===100?'全部检查正常':'存在异常项'],['△','amber','需要关注',state.alerts.length,state.alerts.length?'查看告警中心':'暂无告警']];$('metricCards').innerHTML=items.map((x,i)=>'<article class="metric-card"><div class="metric-top"><span class="metric-icon '+x[1]+'">'+x[0]+'</span><label>'+x[2]+'</label></div><strong>'+esc(x[3])+'</strong><footer><span>'+esc(x[4])+'</span><svg class="mini-line" viewBox="0 0 60 20"><polyline fill="none" stroke="'+(['#526df6','#37c990','#8a6bf5','#f6b73c'][i])+'" stroke-width="1.5" points="0,15 10,12 20,14 30,7 40,10 50,4 60,8"/></svg></footer></article>').join('')}
function renderTechnical(){const m=state.monitor||{},r=runtime(),g=git(),last=state.events.at(-1),items=[['当前分支',g.branch||'—',g.upstream||'无 upstream'],['Git HEAD',g.head||'—','代码基线'],['Gateway PID',r.gateway?.pid||'—',r.gateway?.state||'unknown'],['Active Agents',r.gateway?.activeAgents??'—','gateway_state.json'],['最后事件 ID',m.lastEventId||'—',last?.action||'暂无事件'],['Run ID',last?.runId||'—','当前监控运行'],['工作树变化',g.entries?.length||0,'Git status entries'],['日志事件',m.countsBySource?.log||0,'normalized'],['进程事件',m.countsBySource?.process||0,'normalized'],['最近证据',last?.evidenceLevel||'—',last?.timestamp||'暂无时间']];$('technicalGrid').innerHTML=items.map(x=>'<div class="technical-item"><label>'+esc(x[0])+'</label><strong title="'+esc(x[1])+'">'+esc(x[1])+'</strong><small title="'+esc(x[2])+'">'+esc(x[2])+'</small></div>').join('')}
function renderChart(){const list=state.events.slice(-60),buckets=Array.from({length:12},()=>({all:0,task:0}));list.forEach((e,i)=>{const b=Math.min(11,Math.floor(i/Math.max(1,list.length/12)));buckets[b].all++;if(['task','tool'].includes(category(e)))buckets[b].task++});const max=Math.max(1,...buckets.map(b=>b.all)),pts=key=>buckets.map((b,i)=>(i*60+10)+','+(185-b[key]/max*145)).join(' '),area='10,185 '+pts('all')+' 670,185';$('trendChart').innerHTML='<svg viewBox="0 0 680 200" preserveAspectRatio="none"><defs><linearGradient id="areaBlue" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#526df6" stop-opacity=".18"/><stop offset="1" stop-color="#526df6" stop-opacity="0"/></linearGradient></defs>'+[40,75,110,145,180].map(y=>'<line class="grid-line" x1="10" x2="670" y1="'+y+'" y2="'+y+'"/>').join('')+'<polygon class="area-blue" points="'+area+'"/><polyline class="chart-blue" points="'+pts('all')+'"/><polyline class="chart-green" points="'+pts('task')+'"/></svg>'}
function renderTask(){const t=task();if(!t){$('taskBadge').textContent='等待信号';$('currentTask').innerHTML='<div class="empty">暂无可识别任务。新的任务 ID 或工具活动出现后会自动更新。</div>';return}$('taskBadge').textContent=t.status==='COMPLETED'?'已完成':t.status==='ERROR'?'有错误':'执行中';const steps=[['识别任务',t.stages.taskObserved],['工具活动',t.stages.toolObserved],['代码变化',t.stages.workspaceChanged],['完成标记',t.stages.completionObserved]];$('currentTask').innerHTML='<div class="task-main"><div><small class="eyebrow">'+esc(t.taskId)+'</small><h3>'+esc(friendly({action:t.lastAction}))+'</h3><p>最近活动 '+rel(t.lastSeenAt)+' · 只按可观察证据计进度</p></div><div class="progress-ring" style="--progress:'+t.observedProgress+'"><strong>'+t.observedProgress+'%</strong></div></div><div class="task-steps">'+steps.map(s=>'<div class="task-step '+(s[1]?'done':'')+'">'+(s[1]?'✓ ':'○ ')+s[0]+'</div>').join('')+'</div>'}
function renderHealth(){const r=runtime(),h=health(),ports=r.ports||[],proc=r.processes||[],items=[['Gateway',r.gateway?.state==='running',r.gateway?.state||'未知'],['健康接口',r.health?.ok===true,r.health?.status?'HTTP '+r.health.status:'不可用'],['8642 / 60825',ports.length>0&&ports.every(p=>p.listening),ports.filter(p=>p.listening).length+'/'+ports.length+' 正常'],['Hermes 进程',proc.some(p=>p.name==='Hermes'),proc.filter(p=>p.name==='Hermes').length+' 个']];$('healthScore').textContent=h.score;$('healthList').innerHTML=items.map(x=>'<div class="health-row"><i class="'+(x[1]?'ok':'')+'"></i><span>'+x[0]+'</span><strong>'+esc(x[2])+'</strong></div>').join('')}
function renderAssistant(){const h=health(),t=task(),critical=state.alerts.filter(a=>a.severity==='critical').length;let title='Hermes 当前运行平稳',text='没有发现严重问题，监控会继续观察任务、端口和代码变化。';if(critical){title='发现 '+critical+' 个严重告警';text='先查看告警证据和整改建议，不要直接按日志关键词修改代码。'}else if(t?.status==='ACTIVE'){title='Hermes 正在执行任务';text='任务 '+t.taskId+' 的可观察进度为 '+t.observedProgress+'%。'}else if(h.score<100){title='部分健康检查未通过';text='请查看运行健康卡片中标红的项目。'}$('assistantMessage').innerHTML='<strong>'+esc(title)+'</strong><p>'+esc(text)+'</p>';$('assistantInsights').innerHTML=[['任务状态',t?t.status+' · '+t.observedProgress+'%':'等待任务信号'],['仓库状态',(git().entries?.length||0)+' 项工作树变化'],['审批证据',state.alerts.some(a=>a.ruleId==='approval-missing')?'存在缺失引用':'未发现缺失告警']].map(x=>'<div class="insight"><strong>'+x[0]+'</strong><span>'+esc(x[1])+'</span></div>').join('');$('assistantDot').style.background=critical?'var(--red)':h.score<100?'var(--amber)':'var(--green)'}
function renderRisk(){const values=state.monitor?.countsByRisk||{},keys=['R0_READ_ONLY','R1_REVERSIBLE_WORKSPACE_WRITE','R2_STATEFUL_OPERATION','R3_DESTRUCTIVE_OR_SYSTEM_CHANGE','R4_PRODUCTION_OR_REAL_MONEY'],colors=['#526df6','#37c990','#f6b73c','#ef6476','#8a6bf5'],total=keys.reduce((n,k)=>n+(values[k]||0),0)||1;let at=0,segments=keys.map((k,i)=>{const next=at+(values[k]||0)/total*100,s=colors[i]+' '+at+'% '+next+'%';at=next;return s});$('riskDonut').style.background='conic-gradient('+segments.join(',')+')';$('riskDonut').innerHTML='<div><strong>'+state.monitor?.totalEvents+'</strong><span>事件</span></div>';$('riskLegend').innerHTML=keys.map((k,i)=>'<div class="legend-row"><i style="background:'+colors[i]+'"></i><span>'+k.split('_')[0]+'</span><b>'+(values[k]||0)+'</b></div>').join('')}
function renderAlerts(){const list=state.alerts.slice().reverse().slice(0,5),n=list.length;$('alertCount').textContent=n;$('navAlertCount').textContent=n;$('bellCount').textContent=n;$('alertList').innerHTML=n?list.map(a=>'<div class="alert-item '+a.severity+'"><i></i><div><strong>'+esc(a.title)+'</strong><small>'+esc(a.message)+' · '+a.occurrences+' 次</small></div></div>').join(''):'<div class="empty">暂无告警</div>'}
function remediationText(r){return ['整改建议：'+r.title,'当前判断：'+r.diagnosis,'可能影响：'+r.possibleImpact,'建议步骤：',...r.steps.map((x,i)=>(i+1)+'. '+x),'验证方式：',...r.verification.map(x=>'- '+x),'需要审批：'+(r.requiresApproval?'是':'否')].join('\\n')}function renderRecommendations(){const list=state.recommendations.slice().reverse().slice(0,6);$('recommendationCount').textContent=list.length+' 条';$('recommendations').innerHTML=list.length?list.map(r=>'<article class="recommendation"><span class="priority '+(r.priority==='HIGH'?'high':'')+'">'+r.priority+' · '+r.status+'</span><h3>'+esc(r.title)+'</h3><p>'+esc(r.diagnosis)+'</p><footer><span class="source-tag">'+(r.requiresApproval?'需要审批':'可先只读检查')+'</span><button data-rec="'+esc(r.recommendationId)+'">复制建议</button></footer></article>').join(''):'<div class="empty">暂无整改建议</div>';document.querySelectorAll('[data-rec]').forEach(b=>b.addEventListener('click',async()=>{const r=state.recommendations.find(x=>x.recommendationId===b.dataset.rec);if(r){await navigator.clipboard.writeText(remediationText(r));b.textContent='已复制'}}))}
function redactDraftText(value){return String(value||'').replace(/\\bBearer\\s+[A-Za-z0-9._~+/=-]+/gi,'Bearer [REDACTED]').replace(/\\b(api[_-]?key|authorization|cookie|password|passwd|private[_-]?key|secret|token)\\b\\s*[:=]\\s*[^\\s,;]+/gi,(match,key)=>key+'=[REDACTED]')}
function selectedCollaborationEvidence(){const selected=state.events.filter(e=>state.collaborationEvidence.has(e.eventId));return selected.length?selected:state.events.slice(-8)}
function invalidateCollaboration(){state.collaborationBundle=null;state.collaborationPrompt='';$('collaborationStatus').textContent='有未生成的更改'}
function buildCollaborationBundle(context){const objective=redactDraftText($('collaborationObjective').value).trim()||'基于附带的可观察证据评估当前状态，给出下一步建议；任何写操作都必须单独说明风险并等待明确授权。';const includeTask=$('includeTask').checked,includeAlerts=$('includeAlerts').checked,includeRuntime=$('includeRuntime').checked;return{schemaVersion:'1.0',kind:'dsbot.collaboration.handoff',generatedAt:new Date().toISOString(),objective,routing:{target:$('collaborationTarget').value,requestedActionCeiling:$('collaborationRisk').value},authorization:{thisBundleGrantsApproval:false,productionChangesRequireSeparateAuthorization:true},capabilities:{canExecuteCommands:false,canSendMessages:false,canPersistDrafts:false},source:{endpoint:'/api/collaboration-context',generatedAt:context.generatedAt,channel:context.channel},context:{task:includeTask?context.activity?.currentTask||null:null,runtime:includeRuntime?context.monitor?.lastEventBySource?.process?.after||null:null,monitor:{totalEvents:context.monitor?.totalEvents||0,lastEventAt:context.monitor?.lastEventAt||null,countsByRisk:context.monitor?.countsByRisk||{}},alerts:includeAlerts?context.recentAlerts:[],recommendations:includeAlerts?context.recommendations:[],evidence:selectedCollaborationEvidence()}}}
function collaborationPrompt(bundle){const target=bundle.routing.target==='codex-hermes'?'Codex 负责分析与统筹，Hermes 负责经授权后的轻量执行':bundle.routing.target==='codex'?'仅交给 Codex 分析':'仅交给 Hermes 处理',fence=String.fromCharCode(96).repeat(3);return['# DSbot 协同任务','','## 目标',bundle.objective,'','## 协作路由',target,'建议动作上限：'+bundle.routing.requestedActionCeiling,'','## 硬性安全边界','- 本协同包不构成审批或授权。','- 不得发送真实消息、执行命令、修改生产或持久化草稿，除非另行获得明确授权。','- 先验证事实，再区分 VERIFIED_OBSERVED 与 INFERRED_FROM_OBSERVED。','- 所有拟议写操作必须列出影响、回滚与验证方法。','','## 可追溯上下文',fence+'json',JSON.stringify(bundle,null,2),fence].join(String.fromCharCode(10))}
function renderCollaborationEvidence(){const selected=state.events.filter(e=>state.collaborationEvidence.has(e.eventId));$('collaborationEvidenceCount').textContent=selected.length?selected.length+' 条':'0 条；生成时自动使用最近 8 条';$('collaborationEvidenceList').innerHTML=selected.length?selected.map(e=>'<span class="evidence-chip" title="'+esc(e.eventId)+'">'+esc(friendly(e))+' <button type="button" data-remove-evidence="'+esc(e.eventId)+'" aria-label="移除证据">×</button></span>').join(''):'<span class="evidence-empty">可从活动详情中加入关键证据</span>';document.querySelectorAll('[data-remove-evidence]').forEach(button=>button.addEventListener('click',()=>{state.collaborationEvidence.delete(button.dataset.removeEvidence);invalidateCollaboration();renderCollaborationEvidence()}))}
async function generateCollaboration(){const button=$('generateCollaboration');const original=button.textContent;button.disabled=true;button.textContent='读取上下文…';try{const response=await fetch('/api/collaboration-context');if(!response.ok)throw new Error('HTTP '+response.status);state.collaborationContext=await response.json();state.collaborationBundle=buildCollaborationBundle(state.collaborationContext);state.collaborationPrompt=collaborationPrompt(state.collaborationBundle);$('collaborationPreview').textContent=state.collaborationPrompt;$('collaborationStatus').textContent='已生成 · '+new Date(state.collaborationBundle.generatedAt).toLocaleTimeString()+' · 未授予审批';button.textContent='已生成 ✓';return true}catch(error){$('collaborationStatus').textContent='生成失败：'+String(error?.message||error);button.textContent='生成失败';return false}finally{button.disabled=false;setTimeout(()=>button.textContent=original,1300)}}
async function downloadCollaboration(){if(!(await generateCollaboration()))return;const blob=new Blob([JSON.stringify(state.collaborationBundle,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download='dsbot-collaboration-'+new Date().toISOString().replace(/[:.]/g,'-')+'.json';link.click();setTimeout(()=>URL.revokeObjectURL(url),0)}
function filtered(){const q=$('search').value.toLowerCase();return state.events.filter(e=>(state.filter==='all'||category(e)===state.filter)&&(!q||JSON.stringify([e.action,e.target,e.taskId]).toLowerCase().includes(q))).slice().reverse().slice(0,20)}function statusFor(e){const c=category(e);return c==='error'?['错误','error']:c==='change'?['已变化','warn']:c==='task'||c==='tool'?['进行中','']:['已记录','']}function renderEvents(){const list=filtered();$('activityCaption').textContent='显示 '+list.length+' 条 · '+(state.paused?'已暂停':'实时更新');$('events').innerHTML=list.length?list.map(e=>{const st=statusFor(e);return'<div class="activity-row" data-event="'+esc(e.eventId)+'"><div class="activity-info"><span class="activity-icon">'+({error:'!',change:'△',tool:'⌘',task:'◎',other:'·'}[category(e)])+'</span><div><strong>'+esc(friendly(e))+'</strong><small>'+esc(e.taskId?'任务 '+e.taskId:(e.target||'可观察事件'))+'</small></div></div><span class="source-tag">'+esc(source(e.source))+'</span><span class="status-tag '+st[1]+'">'+st[0]+'</span><span class="source-tag">'+rel(e.timestamp)+'</span><span class="row-more">•••</span></div>'}).join(''):'<div class="empty">没有符合条件的活动</div>';document.querySelectorAll('[data-event]').forEach(row=>row.addEventListener('click',()=>openEvent(row.dataset.event)))}
const riskMeaning={R0_READ_ONLY:'只读观察，没有修改系统或项目',R1_REVERSIBLE_WORKSPACE_WRITE:'发生了可撤销的工作区写入',R2_STATEFUL_OPERATION:'涉及会改变外部状态的操作',R3_DESTRUCTIVE_OR_SYSTEM_CHANGE:'可能造成破坏或系统级变化',R4_PRODUCTION_OR_REAL_MONEY:'涉及生产环境或真实资金'};const evidenceMeaning={VERIFIED_OBSERVED:'监控直接捕获并验证的事实',INFERRED_FROM_OBSERVED:'依据已观察事实作出的推断，并非直接事实'};
function resultMeaning(e){if(e.result?.ok===true)return'事件结果被记录为成功。';if(e.result?.ok===false)return'事件结果被记录为失败；需要查看 error 或 message 字段确认表现。';if(e.after&&e.before)return'记录包含变化前和变化后的快照，可用来比较发生了什么改变。';if(e.after)return'记录包含观察后的状态快照。';return'该记录没有提供明确的成功/失败结果，只能确认事件被观察到。'}function limitation(e){if(e.source==='filesystem'||e.source==='git')return'它能证明文件或 Git 状态发生变化，但不能单独证明是谁修改、为什么修改或修改是否正确。';if(e.action==='log.error')return'它能证明日志出现错误信号，但错误文本可能是根因，也可能只是后续症状。';if(e.source==='process')return'它能证明采样时刻的进程、端口或健康状态，不能保证采样间隔内始终如此。';return'这条证据只证明监控实际观察到的内容，不能据此推断 Agent 的隐藏思考或未记录动作。'}function evidenceExplanation(e){return[['这是什么','这是一条编号为 '+e.eventId+' 的可观察事件记录，动作是“'+friendly(e)+'”。'],['从哪里来','监控从“'+source(e.source)+'”采集，记录时间为 '+new Date(e.timestamp).toLocaleString()+'。'],['涉及什么',e.target?'涉及目标：'+e.target+'。':e.taskId?'与任务 '+e.taskId+' 关联。':'没有提供明确目标或任务关联。'],['结果怎么看',resultMeaning(e)],['风险含义',(riskMeaning[e.riskClass]||'未识别的风险分级')+'（原始等级：'+e.riskClass+'）。'],['证据强度',(evidenceMeaning[e.evidenceLevel]||'未识别的证据级别')+'（原始级别：'+e.evidenceLevel+'）。'],['不能推出',limitation(e),'caution']]}
function explanationText(e){return evidenceExplanation(e).map(x=>x[0]+'：'+x[1]).join(String.fromCharCode(10))}function explain(e){if(e.action==='log.error')return'日志出现错误信号；它可能是根因，也可能是后续症状，需要结合上下文确认。';if(e.action==='git.head_changed')return'Git HEAD 发生变化，代表代码基线改变，但不能仅凭这一点确认执行者。';if(e.source==='filesystem')return'项目文件发生变化，监控只记录事实，不自动归因。';return'这是监控从 '+source(e.source)+' 捕获到的可观察证据。'}function openEvent(id){const e=state.events.find(x=>x.eventId===id);if(!e)return;state.selected=e;$('dialogTitle').textContent=friendly(e);$('dialogExplain').textContent=explain(e);$('dialogFacts').innerHTML=[['时间',new Date(e.timestamp).toLocaleString()],['来源',source(e.source)],['风险',e.riskClass],['任务 ID',e.taskId||'未关联'],['审批引用',e.approvalId||'未提供'],['目标',e.target||'无']].map(x=>'<div class="fact"><label>'+x[0]+'</label><strong>'+esc(x[1])+'</strong></div>').join('');$('dialogCodeExplanation').innerHTML=evidenceExplanation(e).map(x=>'<div class="explanation-row '+(x[2]||'')+'"><b>'+esc(x[0])+'</b><p>'+esc(x[1])+'</p></div>').join('');$('dialogJson').textContent=JSON.stringify(e,null,2);$('addToCollaborationButton').textContent=state.collaborationEvidence.has(e.eventId)?'从协同包移除':'加入协同包';$('eventDialog').showModal()}
function renderWelcome(){const h=health(),t=task();$('welcomeText').textContent=t?.status==='ACTIVE'?'Hermes 正在执行任务，下面是实时可观察进度。':h.score===100?'Hermes 运行正常，当前等待新的任务活动。':'检测到部分运行检查异常，请查看右侧助手。';$('lastUpdated').textContent='最近更新 '+rel(state.monitor?.lastEventAt)}function render(){renderWelcome();renderMetrics();renderTechnical();renderChart();renderTask();renderHealth();renderAssistant();renderRisk();renderAlerts();renderRecommendations();renderEvents();renderCollaborationEvidence()}
async function refresh(manual=false){if(state.paused&&!manual)return;const button=$('refreshButton');if(manual){button.disabled=true;button.textContent='刷新中…'}try{const response=await fetch('/api/state');if(!response.ok)throw new Error('HTTP '+response.status);const d=await response.json();state.monitor=d.monitor;state.activity=d.activity||{recentTasks:[]};state.events=d.recentEvents||[];state.alerts=d.recentAlerts||[];state.recommendations=d.recommendations||[];setConnection(true);render();if(manual)button.textContent='已刷新 ✓'}catch{setConnection(false);if(manual)button.textContent='刷新失败'}finally{if(manual)setTimeout(()=>{button.disabled=false;button.textContent='立即刷新'},1100)}}let timer;const schedule=()=>{clearTimeout(timer);timer=setTimeout(refresh,120)};function setConnection(ok){$('connection').className='connection '+(ok?'online':'offline');$('connection').innerHTML='<i></i><span>'+(state.paused?'实时刷新已暂停':ok?'实时连接':'连接断开')+'</span>'}
function setTechnical(enabled){state.technical=enabled;document.body.classList.toggle('technical',enabled);$('modeButton').classList.toggle('mode-active',enabled);$('modeButton').setAttribute('aria-pressed',String(enabled));$('modeButton').textContent=enabled?'退出专业视图':'专业视图';if(enabled)$('technicalPanel').scrollIntoView({behavior:'smooth',block:'center'})}function flash(id){const el=$(id);el.classList.remove('flash');void el.offsetWidth;el.classList.add('flash');el.scrollIntoView({behavior:'smooth',block:'center'})}async function copyWithFeedback(button,value,success){const original=button.textContent;try{await navigator.clipboard.writeText(value);button.textContent=success}catch{button.textContent='复制失败'}setTimeout(()=>button.textContent=original,1300)}
$('pauseButton').addEventListener('click',()=>{state.paused=!state.paused;$('pauseButton').textContent=state.paused?'▶':'Ⅱ';$('pauseButton').classList.toggle('mode-active',state.paused);$('pauseButton').setAttribute('aria-pressed',String(state.paused));setConnection($('connection').classList.contains('online'));if(!state.paused)refresh();renderEvents()});$('refreshButton').addEventListener('click',()=>{state.paused=false;$('pauseButton').textContent='Ⅱ';$('pauseButton').classList.remove('mode-active');refresh(true)});$('modeButton').addEventListener('click',()=>setTechnical(!state.technical));document.querySelector('.bell').addEventListener('click',()=>flash('alerts'));$('search').addEventListener('input',renderEvents);document.querySelectorAll('.nav-item').forEach(a=>a.addEventListener('click',()=>{document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));a.classList.add('active')}));document.querySelectorAll('.chip').forEach(b=>b.addEventListener('click',()=>{document.querySelectorAll('.chip').forEach(x=>x.classList.remove('active'));b.classList.add('active');state.filter=b.dataset.filter;renderEvents()}));document.querySelectorAll('[data-jump]').forEach(b=>b.addEventListener('click',()=>document.getElementById(b.dataset.jump)?.scrollIntoView({behavior:'smooth'})));$('showTechnical').addEventListener('click',()=>setTechnical(true));$('copyStatus').addEventListener('click',()=>copyWithFeedback($('copyStatus'),JSON.stringify({monitor:state.monitor,activity:state.activity,alerts:state.alerts,recommendations:state.recommendations},null,2),'状态已复制 ✓'));$('scrollTop').addEventListener('click',()=>scrollTo({top:0,behavior:'smooth'}));$('addToCollaborationButton').addEventListener('click',()=>{if(!state.selected)return;const id=state.selected.eventId;if(state.collaborationEvidence.has(id))state.collaborationEvidence.delete(id);else state.collaborationEvidence.add(id);invalidateCollaboration();$('addToCollaborationButton').textContent=state.collaborationEvidence.has(id)?'从协同包移除':'加入协同包';renderCollaborationEvidence()});['collaborationObjective','collaborationTarget','collaborationRisk','includeTask','includeAlerts','includeRuntime'].forEach(id=>$(id).addEventListener('input',invalidateCollaboration));$('generateCollaboration').addEventListener('click',generateCollaboration);$('copyCollaboration').addEventListener('click',async()=>{if(!(await generateCollaboration()))return;copyWithFeedback($('copyCollaboration'),state.collaborationPrompt,'Prompt 已复制 ✓')});$('downloadCollaboration').addEventListener('click',downloadCollaboration);$('clearCollaborationEvidence').addEventListener('click',()=>{state.collaborationEvidence.clear();state.collaborationBundle=null;state.collaborationPrompt='';$('collaborationPreview').textContent='尚未生成。先写目标，也可以从“可观察活动”详情中加入关键证据。';$('collaborationStatus').textContent='未生成';renderCollaborationEvidence()});$('copyExplanationButton').addEventListener('click',()=>{if(state.selected)copyWithFeedback($('copyExplanationButton'),explanationText(state.selected),'说明已复制 ✓')});$('copyButton').addEventListener('click',()=>{if(state.selected)copyWithFeedback($('copyButton'),JSON.stringify(state.selected,null,2),'证据已复制 ✓')});document.addEventListener('keydown',e=>{if(e.ctrlKey&&e.key.toLowerCase()==='k'){e.preventDefault();$('search').focus()}});setInterval(()=>$('clock').textContent=new Date().toLocaleTimeString(),1000);
function initAmbient(){const canvas=$('ambientCanvas'),ctx=canvas.getContext('2d'),reduced=matchMedia('(prefers-reduced-motion: reduce)').matches,pointer={x:-9999,y:-9999},particles=[];let width=0,height=0,dpr=1,frameId=0;function seed(){particles.length=0;const count=reduced?22:Math.min(88,Math.max(42,Math.floor(width/19)));for(let i=0;i<count;i++)particles.push({x:Math.random()*width,y:Math.random()*height,vx:(Math.random()-.5)*.22,vy:(Math.random()-.5)*.22,r:Math.random()*1.35+.45,a:Math.random()*.42+.18})}function resize(){width=innerWidth;height=innerHeight;dpr=Math.min(devicePixelRatio||1,1.7);canvas.width=Math.floor(width*dpr);canvas.height=Math.floor(height*dpr);canvas.style.width=width+'px';canvas.style.height=height+'px';ctx.setTransform(dpr,0,0,dpr,0,0);seed()}function draw(){ctx.clearRect(0,0,width,height);for(let i=0;i<particles.length;i++){const p=particles[i];if(!reduced){p.x+=p.vx;p.y+=p.vy;const dx=pointer.x-p.x,dy=pointer.y-p.y,dist=Math.hypot(dx,dy);if(dist<150&&dist>1){p.x-=dx/dist*.12;p.y-=dy/dist*.12}if(p.x<0)p.x=width;if(p.x>width)p.x=0;if(p.y<0)p.y=height;if(p.y>height)p.y=0}ctx.beginPath();ctx.fillStyle='rgba(132,158,255,'+p.a+')';ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();for(let j=i+1;j<particles.length;j++){const q=particles[j],dx=p.x-q.x,dy=p.y-q.y,d2=dx*dx+dy*dy;if(d2<10500){ctx.beginPath();ctx.strokeStyle='rgba(103,130,225,'+((1-d2/10500)*.09)+')';ctx.lineWidth=.6;ctx.moveTo(p.x,p.y);ctx.lineTo(q.x,q.y);ctx.stroke()}}}if(!reduced)frameId=requestAnimationFrame(draw)}resize();draw();addEventListener('resize',()=>{cancelAnimationFrame(frameId);resize();draw()},{passive:true});addEventListener('pointermove',e=>{pointer.x=e.clientX;pointer.y=e.clientY;document.body.style.setProperty('--mouse-x',e.clientX+'px');document.body.style.setProperty('--mouse-y',e.clientY+'px')},{passive:true});addEventListener('pointerleave',()=>{pointer.x=-9999;pointer.y=-9999})}initAmbient();document.addEventListener('pointermove',e=>{const card=e.target instanceof Element?e.target.closest('.card,.metric-card'):null;if(!card)return;const r=card.getBoundingClientRect();card.style.setProperty('--card-x',e.clientX-r.left+'px');card.style.setProperty('--card-y',e.clientY-r.top+'px')},{passive:true});
const stream=new EventSource('/api/events');stream.addEventListener('open',()=>setConnection(true));['observable','alert','recommendation'].forEach(n=>stream.addEventListener(n,schedule));stream.addEventListener('error',()=>setConnection(false));refresh();
`;
